using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public interface IInspectionDataService
{
    Task<List<ConstructionSite>> GetSitesAsync();
    Task SaveSiteAsync(ConstructionSite site);
    Task DeleteSiteAsync(string siteId);

    Task<List<Inspection>> GetInspectionsAsync(string? siteId = null);
    Task<Inspection?> GetInspectionAsync(string inspectionId);
    Task SaveInspectionAsync(Inspection inspection);
    Task DeleteInspectionAsync(string inspectionId);

    Task<List<Inspection>> GetUnsyncedInspectionsAsync();
    Task MarkAsSyncedAsync(string inspectionId);
}

using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

/// <summary>
/// IndexedDB-backed data service for offline-first storage.
/// </summary>
public class LocalStorageService : IInspectionDataService
{
    private readonly IJSRuntime _js;

    public LocalStorageService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task<List<ConstructionSite>> GetSitesAsync()
    {
        return await GetAllFromStore<ConstructionSite>("sites");
    }

    public async Task SaveSiteAsync(ConstructionSite site)
    {
        await PutToStore("sites", site.Id, site);
    }

    public async Task DeleteSiteAsync(string siteId)
    {
        await DeleteFromStore("sites", siteId);
    }

    public async Task<List<Inspection>> GetInspectionsAsync(string? siteId = null)
    {
        var all = await GetAllFromStore<Inspection>("inspections");
        if (siteId is not null)
            return all.Where(i => i.SiteId == siteId).OrderByDescending(i => i.CreatedAt).ToList();
        return all.OrderByDescending(i => i.CreatedAt).ToList();
    }

    public async Task<Inspection?> GetInspectionAsync(string inspectionId)
    {
        return await GetFromStore<Inspection>("inspections", inspectionId);
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        await PutToStore("inspections", inspection.Id, inspection);
    }

    public async Task DeleteInspectionAsync(string inspectionId)
    {
        await DeleteFromStore("inspections", inspectionId);
    }

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        var all = await GetAllFromStore<Inspection>("inspections");
        return all.Where(i => !i.IsSynced && i.IsComplete).ToList();
    }

    public async Task MarkAsSyncedAsync(string inspectionId)
    {
        var inspection = await GetInspectionAsync(inspectionId);
        if (inspection is not null)
        {
            inspection.IsSynced = true;
            await SaveInspectionAsync(inspection);
        }
    }

    private async Task<List<T>> GetAllFromStore<T>(string storeName)
    {
        var json = await _js.InvokeAsync<string>("indexedDbHelper.getAll", storeName);
        if (string.IsNullOrEmpty(json)) return new List<T>();
        return JsonSerializer.Deserialize<List<T>>(json, JsonOptions) ?? new List<T>();
    }

    private async Task<T?> GetFromStore<T>(string storeName, string key)
    {
        var json = await _js.InvokeAsync<string>("indexedDbHelper.get", storeName, key);
        if (string.IsNullOrEmpty(json)) return default;
        return JsonSerializer.Deserialize<T>(json, JsonOptions);
    }

    private async Task PutToStore<T>(string storeName, string key, T value)
    {
        var json = JsonSerializer.Serialize(value, JsonOptions);
        await _js.InvokeVoidAsync("indexedDbHelper.put", storeName, key, json);
    }

    private async Task DeleteFromStore(string storeName, string key)
    {
        await _js.InvokeVoidAsync("indexedDbHelper.delete", storeName, key);
    }

    private static JsonSerializerOptions JsonOptions => new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
        WriteIndented = false
    };
}

using System.Net.Http.Json;
using Microsoft.JSInterop;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

/// <summary>
/// Monitors connectivity and syncs completed inspections to the server when online.
/// </summary>
public class SyncService : IDisposable
{
    private readonly IInspectionDataService _dataService;
    private readonly HttpClient _httpClient;
    private readonly IJSRuntime _js;
    private Timer? _syncTimer;
    private bool _isSyncing;

    public event Action<SyncStatus>? OnSyncStatusChanged;
    public SyncStatus CurrentStatus { get; private set; } = SyncStatus.Idle;
    public int PendingCount { get; private set; }

    public SyncService(IInspectionDataService dataService, HttpClient httpClient, IJSRuntime js)
    {
        _dataService = dataService;
        _httpClient = httpClient;
        _js = js;
    }

    public void StartBackgroundSync()
    {
        _syncTimer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
    }

    public async Task TrySyncAsync()
    {
        if (_isSyncing) return;
        _isSyncing = true;

        try
        {
            var isOnline = await _js.InvokeAsync<bool>("navigator.onLine.valueOf");
            if (!isOnline)
            {
                UpdateStatus(SyncStatus.Offline);
                return;
            }

            var unsynced = await _dataService.GetUnsyncedInspectionsAsync();
            PendingCount = unsynced.Count;

            if (unsynced.Count == 0)
            {
                UpdateStatus(SyncStatus.Idle);
                return;
            }

            UpdateStatus(SyncStatus.Syncing);

            foreach (var inspection in unsynced)
            {
                try
                {
                    var response = await _httpClient.PostAsJsonAsync("api/inspections/sync", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        await _dataService.MarkAsSyncedAsync(inspection.Id);
                        PendingCount--;
                    }
                }
                catch
                {
                    // Network error during sync — will retry next cycle
                    UpdateStatus(SyncStatus.Offline);
                    return;
                }
            }

            UpdateStatus(SyncStatus.Synced);
        }
        catch
        {
            UpdateStatus(SyncStatus.Offline);
        }
        finally
        {
            _isSyncing = false;
        }
    }

    private void UpdateStatus(SyncStatus status)
    {
        CurrentStatus = status;
        OnSyncStatusChanged?.Invoke(status);
    }

    public void Dispose()
    {
        _syncTimer?.Dispose();
    }
}

public enum SyncStatus
{
    Idle,
    Syncing,
    Synced,
    Offline
}

