arguments.file_text:
@page "/"

<PageTitle>Site Inspector</PageTitle>

<div class="page-header">
    <h1>🏗️ Site Inspector</h1>
    <p class="subtitle">Construction Safety Inspections</p>
</div>

<div class="action-cards">
    <a href="/sites" class="action-card">
        <span class="action-icon">📋</span>
        <span class="action-label">My Sites</span>
    </a>
    <a href="/inspections" class="action-card">
        <span class="action-icon">✅</span>
        <span class="action-label">Inspections</span>
    </a>
    <a href="/new-inspection" class="action-card primary">
        <span class="action-icon">➕</span>
        <span class="action-label">New Inspection</span>
    </a>
</div>

@if (_pendingSync > 0)
{
    <div class="sync-banner">
        <span>📤 @_pendingSync inspection(s) pending sync</span>
    </div>
}

@code {
    [Inject] private IInspectionDataService DataService { get; set; } = default!;
    private int _pendingSync;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            var unsynced = await DataService.GetUnsyncedInspectionsAsync();
            _pendingSync = unsynced.Count;
            StateHasChanged();
        }
    }
}

@page "/sites"

<PageTitle>Construction Sites</PageTitle>

<div class="page-header compact">
    <h2>Construction Sites</h2>
    <button class="btn-icon" @onclick="() => _showAddForm = !_showAddForm">➕</button>
</div>

@if (_showAddForm)
{
    <div class="card form-card">
        <input @bind="_newSiteName" @bind:event="oninput" placeholder="Site name" class="input-field" />
        <input @bind="_newSiteAddress" @bind:event="oninput" placeholder="Address" class="input-field" />
        <div class="form-actions">
            <button class="btn btn-primary" @onclick="AddSite" disabled="@string.IsNullOrWhiteSpace(_newSiteName)">Add Site</button>
            <button class="btn btn-secondary" @onclick="() => _showAddForm = false">Cancel</button>
        </div>
    </div>
}

@if (_sites.Count == 0 && !_showAddForm)
{
    <div class="empty-state">
        <p>No sites yet. Tap ➕ to add your first construction site.</p>
    </div>
}

@foreach (var site in _sites)
{
    <div class="card site-card">
        <div class="site-info" @onclick="() => NavigateToSite(site)">
            <strong>@site.Name</strong>
            <span class="site-address">@site.Address</span>
        </div>
        <button class="btn-icon danger" @onclick="() => DeleteSite(site.Id)">🗑️</button>
    </div>
}

@code {
