@code {
    [Parameter] public string InspectionId { get; set; } = "";
    [Inject] private IInspectionDataService DataService { get; set; } = default!;
    [Inject] private NavigationManager Nav { get; set; } = default!;

    private Inspection? _inspection;
    private string _activeTab = "checklist";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _inspection = await DataService.GetInspectionAsync(InspectionId);
            StateHasChanged();
        }
    }

    private async Task SetStatus(ChecklistItem item, CheckStatus status)
    {
        item.Status = (item.Status == status) ? CheckStatus.NotChecked : status;
        await SaveInspection();
    }

    private async Task HandlePhotoSelected(InputFileChangeEventArgs e)
    {
        if (_inspection == null) return;

        foreach (var file in e.GetMultipleFiles(5))
        {
            // Resize to max 1200px wide for storage efficiency
            var resized = await file.RequestImageFileAsync("image/jpeg", 1200, 1200);
            using var stream = resized.OpenReadStream(maxAllowedSize: 5 * 1024 * 1024);
            using var ms = new MemoryStream();
            await stream.CopyToAsync(ms);
            var base64 = Convert.ToBase64String(ms.ToArray());

            var photo = new InspectionPhoto
            {
                FileName = file.Name,
                DataUrl = $"data:image/jpeg;base64,{base64}",
                TakenAt = DateTime.UtcNow
            };
            _inspection.Photos.Add(photo);
        }

        await SaveInspection();
    }

    private async Task RemovePhoto(InspectionPhoto photo)
    {
        _inspection?.Photos.Remove(photo);
        await SaveInspection();
    }

    private async Task CompleteInspection()
    {
        if (_inspection == null) return;
        _inspection.IsComplete = true;
        await SaveInspection();
    }

    private async Task SaveInspection()
    {
        if (_inspection != null)
        {
            await DataService.SaveInspectionAsync(_inspection);
        }
    }
}

