<PageTitle>New Inspection</PageTitle>

<div class="page-header compact">
    <h2>New Inspection</h2>
</div>

<div class="card form-card">
    <label class="field-label">Construction Site</label>
    @if (_preselectedSiteId != null)
    {
        <div class="input-field readonly">@_selectedSiteName</div>
    }
    else
    {
        <select @bind="_selectedSiteId" class="input-field">
            <option value="">— Select a site —</option>
            @foreach (var site in _sites)
            {
                <option value="@site.Id">@site.Name</option>
            }
        </select>
    }

    <label class="field-label">Inspector Name</label>
    <input @bind="_inspectorName" @bind:event="oninput" placeholder="Your name" class="input-field" />

    <div class="form-actions">
        <button class="btn btn-primary btn-large"
                @onclick="StartInspection"
                disabled="@(string.IsNullOrWhiteSpace(_selectedSiteId) || string.IsNullOrWhiteSpace(_inspectorName))">
            Start Inspection
        </button>
    </div>
</div>

@code {
    [Inject] private IInspectionDataService DataService { get; set; } = default!;
    [Inject] private NavigationManager Nav { get; set; } = default!;
    [SupplyParameterFromQuery] public string? SiteId { get; set; }

    private List<ConstructionSite> _sites = new();
    private string? _preselectedSiteId;
    private string _selectedSiteId = "";
    private string _selectedSiteName = "";
    private string _inspectorName = "";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _sites = await DataService.GetSitesAsync();
            if (SiteId != null)
            {
                _preselectedSiteId = SiteId;
                _selectedSiteId = SiteId;
                var site = _sites.FirstOrDefault(s => s.Id == SiteId);
                _selectedSiteName = site?.Name ?? "Unknown Site";
            }
            StateHasChanged();
        }
    }

    private async Task StartInspection()
    {
        var site = _sites.FirstOrDefault(s => s.Id == _selectedSiteId);
        if (site == null) return;

        var inspection = new Inspection
        {
            SiteId = site.Id,
            SiteName = site.Name,
            InspectorName = _inspectorName.Trim(),
            ChecklistItems = SafetyChecklists.GetDefaultChecklist()
        };

        await DataService.SaveInspectionAsync(inspection);
        Nav.NavigateTo($"/inspection/{inspection.Id}");
    }
}
