<PageTitle>Inspection</PageTitle>

@if (_inspection == null)
{
    <div class="empty-state"><p>Loading...</p></div>
    return;
}

<div class="page-header compact">
    <div>
        <h2>@_inspection.SiteName</h2>
        <span class="subtitle">@_inspection.CreatedAt.ToLocalTime().ToString("MMM d, yyyy h:mm tt") — @_inspection.InspectorName</span>
    </div>
</div>

<!-- Tab Navigation -->
<div class="tab-bar">
    <button class="tab @(_activeTab == "checklist" ? "active" : "")" @onclick='() => _activeTab = "checklist"'>
        Checklist
    </button>
    <button class="tab @(_activeTab == "photos" ? "active" : "")" @onclick='() => _activeTab = "photos"'>
        Photos (@_inspection.Photos.Count)
    </button>
    <button class="tab @(_activeTab == "notes" ? "active" : "")" @onclick='() => _activeTab = "notes"'>
        Notes
    </button>
</div>

@if (_activeTab == "checklist")
{
    <div class="checklist-progress">
        @{ var done = _inspection.ChecklistItems.Count(c => c.Status != CheckStatus.NotChecked); var total = _inspection.ChecklistItems.Count; }
        <div class="progress-bar">
            <div class="progress-fill" style="width: @(total > 0 ? (done * 100 / total) : 0)%"></div>
        </div>
        <span>@done / @total items checked</span>
    </div>

    @foreach (var group in _inspection.ChecklistItems.GroupBy(c => c.Category))
    {
        <div class="checklist-category">
            <h3>@group.Key</h3>
            @foreach (var item in group)
            {
                <div class="checklist-item @item.Status.ToString().ToLower()">
                    <div class="checklist-desc">@item.Description</div>
                    <div class="checklist-actions">
                        <button class="status-btn pass @(item.Status == CheckStatus.Pass ? "selected" : "")"
                                @onclick="() => SetStatus(item, CheckStatus.Pass)">✓</button>
                        <button class="status-btn fail @(item.Status == CheckStatus.Fail ? "selected" : "")"
                                @onclick="() => SetStatus(item, CheckStatus.Fail)">✗</button>
                        <button class="status-btn na @(item.Status == CheckStatus.NotApplicable ? "selected" : "")"
                                @onclick="() => SetStatus(item, CheckStatus.NotApplicable)">N/A</button>
                    </div>
                </div>
            }
        </div>
    }
}
else if (_activeTab == "photos")
{
    <div class="photo-section">
        <label class="btn btn-primary photo-capture-btn">
            📷 Take / Add Photo
            <InputFile OnChange="HandlePhotoSelected" accept="image/*" capture="environment" style="display:none" />
        </label>

        @foreach (var photo in _inspection.Photos)
        {
            <div class="photo-card">
                <img src="@photo.DataUrl" alt="@photo.Caption" class="photo-thumb" />
                <input @bind="photo.Caption" @bind:event="oninput" @bind:after="SaveInspection"
                       placeholder="Add caption..." class="photo-caption-input" />
                <button class="btn-icon danger" @onclick="() => RemovePhoto(photo)">🗑️</button>
            </div>
        }

        @if (_inspection.Photos.Count == 0)
        {
            <div class="empty-state">
                <p>No photos yet. Tap the button above to capture site photos.</p>
            </div>
        }
    </div>
}
else if (_activeTab == "notes")
{
    <div class="notes-section">
        <textarea @bind="_inspection.Notes" @bind:event="oninput" @bind:after="SaveInspection"
                  placeholder="Add inspection notes, observations, or issues..."
                  class="notes-textarea" rows="8"></textarea>
    </div>
}

<div class="bottom-actions">
    @if (!_inspection.IsComplete)
    {
        <button class="btn btn-primary btn-large" @onclick="CompleteInspection">
            ✅ Complete Inspection
        </button>
    }
    else
    {
        <div class="complete-banner">
            <span>✅ Inspection Complete</span>
            @if (_inspection.IsSynced)
            {
                <span class="badge badge-synced">☁️ Synced</span>
            }
            else
            {
                <span class="badge badge-pending">📤 Will sync when online</span>
            }
        </div>
    }
</div>

