@inherits LayoutComponentBase
@inject SyncService SyncService

<div class="app-shell">
    <nav class="bottom-nav">
        <a href="/" class="nav-item">
            <span class="nav-icon">🏠</span>
            <span class="nav-label">Home</span>
        </a>
        <a href="/sites" class="nav-item">
            <span class="nav-icon">🏗️</span>
            <span class="nav-label">Sites</span>
        </a>
        <a href="/new-inspection" class="nav-item primary">
            <span class="nav-icon">➕</span>
            <span class="nav-label">Inspect</span>
        </a>
        <a href="/inspections" class="nav-item">
            <span class="nav-icon">📋</span>
            <span class="nav-label">History</span>
        </a>
    </nav>

    <main class="main-content">
        <div class="sync-indicator @SyncService.CurrentStatus.ToString().ToLower()">
            @switch (SyncService.CurrentStatus)
            {
                case SyncStatus.Offline:
                    <span>📵 Offline</span>
                    break;
                case SyncStatus.Syncing:
                    <span>🔄 Syncing...</span>
                    break;
                case SyncStatus.Synced:
                    <span>☁️ Synced</span>
                    break;
            }
        </div>
        @Body
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    protected override void OnInitialized()
    {
        SyncService.OnSyncStatusChanged += _ => InvokeAsync(StateHasChanged);
        SyncService.StartBackgroundSync();
    }
}

arguments.file_text:
/* Mobile-first layout for construction site inspectors */

:root {
    --primary: #1565c0;
    --primary-light: #1e88e5;
    --success: #2e7d32;
    --danger: #c62828;
    --warning: #f57f17;
    --neutral: #546e7a;
    --bg: #f5f5f5;
    --card-bg: #ffffff;
    --text: #212121;
    --text-muted: #757575;
    --border: #e0e0e0;
    --radius: 12px;
    --nav-height: 64px;
}

* {
    box-sizing: border-box;
    -webkit-tap-highlight-color: transparent;
}

html, body {
    margin: 0;
    padding: 0;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;
    background: var(--bg);
    color: var(--text);
    font-size: 16px;
    overflow-x: hidden;
}

.app-shell {
    min-height: 100dvh;
    display: flex;
    flex-direction: column;
}

.main-content {
    flex: 1;
    padding: 16px;
    padding-bottom: calc(var(--nav-height) + 24px);
    max-width: 600px;
    margin: 0 auto;
    width: 100%;
}

/* Bottom Navigation */
.bottom-nav {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    height: var(--nav-height);
    background: var(--card-bg);
    border-top: 1px solid var(--border);
    display: flex;
    align-items: center;
    justify-content: space-around;
    z-index: 1000;
    padding-bottom: env(safe-area-inset-bottom);
}

.nav-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    text-decoration: none;
    color: var(--text-muted);
    font-size: 11px;
    padding: 8px 12px;
    border-radius: 8px;
    transition: color 0.15s;
}

.nav-item:active {
    background: var(--bg);
}

.nav-item .nav-icon {
    font-size: 22px;
    margin-bottom: 2px;
}

.nav-item.primary .nav-icon {
    background: var(--primary);
    color: white;
    width: 44px;
    height: 44px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-top: -12px;
    font-size: 20px;
}

/* Sync Indicator */
.sync-indicator {
    text-align: center;
    font-size: 12px;
    padding: 4px;
    border-radius: 4px;
    margin-bottom: 8px;
    min-height: 24px;
}

.sync-indicator.offline { color: var(--warning); }
.sync-indicator.syncing { color: var(--primary); }
.sync-indicator.synced { color: var(--success); }
.sync-indicator.idle { display: none; }

/* Page Headers */
.page-header {
    text-align: center;
    margin-bottom: 24px;
}

.page-header h1 {
    margin: 0;
    font-size: 28px;
}

.page-header h2 {
    margin: 0;
    font-size: 22px;
}

.page-header.compact {
    display: flex;
    align-items: center;
    justify-content: space-between;
    text-align: left;
}

.subtitle {
    color: var(--text-muted);
    font-size: 14px;
    margin: 4px 0 0;
}

/* Action Cards (Home Page) */
.action-cards {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 12px;
    margin-bottom: 20px;
}

.action-card {
    background: var(--card-bg);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 24px 16px;
    text-align: center;
    text-decoration: none;
    color: var(--text);
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 8px;
    transition: transform 0.1s;
}

.action-card:active {
    transform: scale(0.97);
}

.action-card.primary {
    grid-column: 1 / -1;
    background: var(--primary);
    color: white;
    border-color: var(--primary);
}

.action-icon {
    font-size: 32px;
}

.action-label {
    font-weight: 600;
    font-size: 15px;
}

/* Cards */
.card {
    background: var(--card-bg);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 16px;
    margin-bottom: 12px;
}

.site-card {
    display: flex;
    align-items: center;
    gap: 12px;
    cursor: pointer;
}

.site-card:active {
    background: var(--bg);
}

.site-info {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.site-address {
    color: var(--text-muted);
    font-size: 13px;
}

.inspection-card {
    display: block;
    text-decoration: none;
    color: var(--text);
}

.inspection-card:active {
    background: var(--bg);
}

.inspection-header {
    display: flex;
    justify-content: space-between;
    align-items: baseline;
    margin-bottom: 8px;
}

.inspection-date {
    color: var(--text-muted);
    font-size: 12px;
}

.inspection-meta {
    display: flex;
    gap: 8px;
    flex-wrap: wrap;
}

/* Badges */
.badge {
    font-size: 11px;
    padding: 2px 8px;
    border-radius: 12px;
    background: var(--bg);
    color: var(--text-muted);
}

.badge-complete { background: #e8f5e9; color: var(--success); }
.badge-progress { background: #e3f2fd; color: var(--primary); }
.badge-synced { background: #e8f5e9; color: var(--success); }
.badge-pending { background: #fff3e0; color: var(--warning); }

/* Forms */
.form-card {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.field-label {
    font-weight: 600;
    font-size: 14px;
    margin-bottom: -4px;
}

.input-field {
    width: 100%;
    padding: 14px 16px;
    border: 1px solid var(--border);
    border-radius: 8px;
