:root {
    --primary: #1565c0;
    --primary-light: #1e88e5;
    --success: #2e7d32;
    --danger: #c62828;
    --warning: #f57f17;
    --neutral: #546e7a;
    --bg: #f5f5f5;
    --card-bg: #ffffff;
    --text: #212121;
    --text-muted: #757575;
    --border: #e0e0e0;
    --radius: 12px;
    --nav-height: 64px;
}

* {
    box-sizing: border-box;
    -webkit-tap-highlight-color: transparent;
}

html, body {
    margin: 0;
    padding: 0;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;
    background: var(--bg);
    color: var(--text);
    font-size: 16px;
    overflow-x: hidden;
}

.app-shell {
    min-height: 100dvh;
    display: flex;
    flex-direction: column;
}

.main-content {
    flex: 1;
