    align-items: center;
    justify-content: space-around;
    z-index: 1000;
    padding-bottom: env(safe-area-inset-bottom);
}

.nav-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    text-decoration: none;
    color: var(--text-muted);
    font-size: 11px;
    padding: 8px 12px;
    border-radius: 8px;
    transition: color 0.15s;
}

.nav-item:active {
    background: var(--bg);
}

.nav-item .nav-icon {
    font-size: 22px;
    margin-bottom: 2px;
}

.nav-item.primary .nav-icon {
    background: var(--primary);
    color: white;
    width: 44px;
    height: 44px;
    border-radius: 50%;
