    align-items: center;
    justify-content: center;
    margin-top: -12px;
    font-size: 20px;
}

/* Sync Indicator */
.sync-indicator {
    text-align: center;
    font-size: 12px;
    padding: 4px;
    border-radius: 4px;
    margin-bottom: 8px;
    min-height: 24px;
}

.sync-indicator.offline { color: var(--warning); }
.sync-indicator.syncing { color: var(--primary); }
.sync-indicator.synced { color: var(--success); }
.sync-indicator.idle { display: none; }

